#!/usr/bin/env bash
set -euo pipefail
INPUT=""; OUT="generated/intelligence/config-surface-graph.json"; JSON_OUT=0
while [[ $# -gt 0 ]]; do case "$1" in --input|-i) INPUT="$2"; shift 2 ;; --output|-o) OUT="$2"; shift 2 ;; --json) JSON_OUT=1; shift ;; *) echo "unknown arg: $1" >&2; exit 64 ;; esac; done
[[ -f "$INPUT" ]] || { echo "--input required" >&2; exit 64; }
mkdir -p "$(dirname "$OUT")"
jq '{schema_version:"1.0",ok:true,references:([.reads[]? | {kind:"code_read",name:.name,path:.path,secret:false}] + [.schemas[]? | {kind:"schema",name:.name,path:.path,secret:false}] + [.defaults[]? | {kind:"default",name:.name,path:.path,secret:false}] + [.docs[]? | {kind:"documentation",name:.name,path:.path,secret:false}] + [.ci[]? | {kind:"ci",name:.name,path:.path,secret:false}] + [.containers[]? | {kind:"container",name:.name,path:.path,secret:false}] + [.deployments[]? | {kind:"deployment",name:.name,path:.path,secret:false}] + [.secrets[]? | {kind:"secret_reference",name:.name,provider:.provider,secret:false,value_recorded:false}]),flags:([.flags[]? | {name,branch_reachable:(if .branch_reachable==null then true else .branch_reachable end),rollout_complete:(if .rollout_complete==null then false else .rollout_complete end),removal_allowed:(((if .branch_reachable==null then true else .branch_reachable end)|not) and (if .rollout_complete==null then false else .rollout_complete end))}]),summary:{references:([.reads[]?,.schemas[]?,.defaults[]?,.docs[]?,.ci[]?,.containers[]?,.deployments[]?,.secrets[]?]|length),secret_value_captures:0,flag_removals_blocked:([.flags[]?|select(.removal_allowed|not)]|length)}}' "$INPUT" > "$OUT"
if [[ "$JSON_OUT" == 1 ]]; then cat "$OUT"; else jq -r '"Config references=\(.summary.references) secrets=\(.summary.secret_value_captures)"' "$OUT"; fi
